/* 마이페이지 수정 */
UPDATE TB_USER
SET
    USER_NM = #{userNm},
    EMAIL = #{email},
    PHONE = #{phone},
    ORG_ID = #{orgId},
    MODIFY_DT = NOW(),
    MDFR_ID = #{userId}
WHERE USER_ID = #{userId}

/* 마이페이지 비밀번호 변경 */
UPDATE TB_USER
SET
    PASSWD = #{passwd},
    PWD_CHG_DT = NOW(),
    LOGIN_FAIL_CNT = 0,
    MODIFY_DT = NOW(),
    MDFR_ID = #{userId}
WHERE USER_ID = #{userId}

mapper.select:
/* 마이페이지 비밀번호 변경 시 현재 비밀번호 확인용 */
SELECT PASSWD
FROM TB_USER
WHERE USER_ID = #{userId}

/* 마이페이지 로그인 이력 조회 mypage.selectUserLoginHistory */
SELECT
    A.IP_ADDR,
    A.USER_AGENT,
    A.RESULT,
    A.FAIL_RSON,
    A.CREATE_DT
FROM TB_AUDIT_LOGIN A
WHERE A.USER_ID = #{userId}

    AND DATE(A.CREATE_DT) >= #{fromDt}


    AND DATE(A.CREATE_DT) <= #{toDt}


    AND A.IP_ADDR LIKE CONCAT('%', #{ipAddr}, '%')


    AND A.RESULT = #{result}

ORDER BY A.CREATE_DT DESC

/* 마이페이지 사진 조회 mypage.selectUserProfileImg */
SELECT
    PROFILE_IMG_NM,
    PROFILE_IMG_PATH
FROM TB_USER
WHERE USER_ID = #{userId}

