/* 마이페이지 사진 업로드 mypage.updateUserProfileImg */
UPDATE TB_USER
SET
    PROFILE_IMG_NM = #{profileImgNm},
    PROFILE_IMG_PATH = #{profileImgPath},
    MODIFY_DT = NOW(),
    MDFR_ID = #{userId}
WHERE USER_ID = #{userId}
